// Code generated by selo gen --lang rust. DO NOT EDIT.

use crate::data::DDD_TO_UF;
use crate::mod11::{self, SeloError};

/// Look up a DDD in the DDD->UF table.
fn ddd_uf(ddd: &str) -> Option<&'static str> {
    DDD_TO_UF.iter().find(|(k, _)| *k == ddd).map(|(_, v)| *v)
}

/// Strip a +55/0055 country prefix, returning the rest or None.
fn national_number(d: &str) -> Option<String> {
    let mut s = d.to_string();
    if s.starts_with("0055") {
        s = s[4..].to_string();
    } else if s.starts_with("55") && s.len() > 11 {
        s = s[2..].to_string();
    }
    if s.is_empty() {
        return None;
    }
    Some(s)
}

/// Report whether value is a valid phone whose DDD maps to a UF.
pub fn validate_phone(value: &str) -> bool {
    let n = match national_number(&mod11::only_digits(value)) {
        Some(n) => n,
        None => return false,
    };
    if n.len() != 10 && n.len() != 11 {
        return false;
    }
    let ddd = &n[0..2];
    if ddd_uf(ddd).is_none() {
        return false;
    }
    if n.len() == 11 && n.as_bytes()[2] != b'9' {
        return false;
    }
    true
}

/// Mask as (DD) NNNNN-NNNN or (DD) NNNN-NNNN, or return an error.
pub fn format_phone(value: &str) -> Result<String, SeloError> {
    let n = match national_number(&mod11::only_digits(value)) {
        Some(n) if n.len() == 10 || n.len() == 11 => n,
        _ => return Err(SeloError::InvalidLength),
    };
    let ddd = &n[0..2];
    if ddd_uf(ddd).is_none() {
        return Err(SeloError::InvalidFormat);
    }
    let sub = &n[2..];
    if sub.len() == 9 {
        return Ok(format!("({}) {}-{}", ddd, &sub[0..5], &sub[5..9]));
    }
    Ok(format!("({}) {}-{}", ddd, &sub[0..4], &sub[4..8]))
}

/// Return the UF for the phone's DDD, or an error.
pub fn origin_phone(value: &str) -> Result<String, SeloError> {
    let n = match national_number(&mod11::only_digits(value)) {
        Some(n) if n.len() == 10 || n.len() == 11 => n,
        _ => return Err(SeloError::InvalidLength),
    };
    let ddd = &n[0..2];
    match ddd_uf(ddd) {
        Some(uf) => Ok(uf.to_string()),
        None => Err(SeloError::InvalidFormat),
    }
}

/// Return a random valid Brazilian phone (unformatted national digits).
pub fn generate_phone() -> String {
    let (ddd, _) = DDD_TO_UF[mod11::rand_int(DDD_TO_UF.len() as u64 - 1) as usize];
    if mod11::rand_int(1) == 0 {
        let mut sub = String::from("9");
        for _ in 0..8 {
            sub.push_str(&mod11::rand_int(9).to_string());
        }
        return format!("{}{}", ddd, sub);
    }
    let mut sub = (2 + mod11::rand_int(3)).to_string();
    for _ in 0..7 {
        sub.push_str(&mod11::rand_int(9).to_string());
    }
    format!("{}{}", ddd, sub)
}

#[cfg(test)]
mod tests {
    use super::*;

    fn vector() -> serde_json::Value {
        let p = concat!(env!("CARGO_MANIFEST_DIR"), "/vectors/phone.json");
        let s = std::fs::read_to_string(p).expect("read vector");
        serde_json::from_str(&s).expect("parse vector")
    }

    #[test]
    fn validate_cases() {
        for case in vector()["validate"].as_array().unwrap() {
            let input = case["input"].as_str().unwrap();
            let valid = case["valid"].as_bool().unwrap();
            assert_eq!(valid, validate_phone(input), "validate {}", input);
        }
    }

    #[test]
    fn format_cases() {
        for case in vector()["format"].as_array().unwrap() {
            let input = case["input"].as_str().unwrap();
            let is_error = case
                .get("error")
                .and_then(|e| e.as_str())
                .map(|e| !e.is_empty())
                .unwrap_or(false);
            if is_error {
                assert!(format_phone(input).is_err(), "format expected err {}", input);
            } else {
                let want = case["output"].as_str().unwrap();
                assert_eq!(want, format_phone(input).unwrap(), "format {}", input);
            }
        }
    }

    #[test]
    fn origin_cases() {
        if let Some(arr) = vector().get("origin").and_then(|o| o.as_array()) {
            for case in arr {
                let input = case["input"].as_str().unwrap();
                let want = case["output"].as_str().unwrap();
                assert_eq!(want, origin_phone(input).unwrap(), "origin {}", input);
            }
        }
    }

    #[test]
    fn generate_round_trip() {
        for _ in 0..100 {
            let v = generate_phone();
            assert!(validate_phone(&v), "generate produced invalid: {}", v);
        }
    }
}
